import StatCard from "../components/ui/StatCard";

const AdminDashboardPage = ({ rooms, students }) => {
  const totalRooms = rooms.length;
  const allotted = rooms.filter(r => r.occupants.length > 0).length;
  const available = rooms.filter(r => r.occupants.length < r.capacity).length;
  const assignedStudents = students.filter(s => s.roomId).length;

  return (
    <div>
      <h2 style={{ fontSize: 24, fontWeight: 800, color: "#1e293b", marginBottom: 24 }}>Dashboard Overview</h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 16, marginBottom: 32 }}>
        <StatCard label="Total Rooms" value={totalRooms} icon="grid" color="#3b82f6" />
        <StatCard label="Rooms Allotted" value={allotted} icon="bed" color="#8b5cf6" />
        <StatCard label="Available Rooms" value={available} icon="check" color="#22c55e" />
        <StatCard label="Total Students" value={students.length} icon="users" color="#f59e0b" />
        <StatCard label="Assigned Students" value={assignedStudents} icon="award" color="#06b6d4" />
      </div>
    </div>
  );
};

export default AdminDashboardPage;
